bool canConstruct(char* ransomNote, char* magazine) {
    int cnt[26] = {0};
    for (int i = 0; magazine[i]; i++) cnt[magazine[i]-'a']++;
    for (int i = 0; ransomNote[i]; i++) if (--cnt[ransomNote[i]-'a'] < 0) return false;
    return true;
}
